Three tiers, each more aggressive, triggered by token usage ratios:

```rust
use crate::backend::types::{Message, Role};

/// Rough token estimate: ~4 chars per token.
fn estimate_tokens(text: &str) -> usize {
    (text.len() / 4).max(1)
}

/// Check which compaction tier is needed.
pub fn should_compact(estimated_tokens: usize, max_context: usize) -> Option<u8> {
    if max_context == 0 { return Some(3); }
    let ratio = (estimated_tokens * 100) / max_context;
    if ratio > 95 { Some(5) }      // emergency truncation
    else if ratio > 85 { Some(3) } // summarize compact
    else if ratio > 70 { Some(2) } // snip compact
    else { None }
}

/// Tier 1 - Microcompact: replace old tool results with one-line placeholders.
/// Runs before every LLM call, zero model calls, zero latency.
pub fn micro_compact(messages: &mut Vec<Message>) -> usize {
    let tool_indices: Vec<usize> = messages.iter().enumerate()
        .filter(|(_, m)| m.role == Role::Tool)
        .map(|(i, _)| i).collect();

    if tool_indices.len() <= 3 { return 0; }
    let cutoff = tool_indices.len() - 3;
    let mut compacted = 0;

    for &idx in &tool_indices[..cutoff] {
        let msg = &messages[idx];
        if msg.content.starts_with("[Previous: used ") { continue; }
        // Find tool name from matching assistant message
        let tool_name = find_tool_name(messages, &msg.tool_call_id, idx)
            .unwrap_or("tool".into());
        // Exception: preserve file_read results (reference material)
        if tool_name == "file_read" { continue; }
        messages[idx].content = format!("[Previous: used {tool_name}]");
        compacted += 1;
    }
    compacted
}

/// Tier 2 - Snip: remove oldest messages, save to transcript first.
pub fn snip_compact(messages: &mut Vec<Message>, project_path: &Path,
    keep_recent: usize) -> Result<usize> {
    let keep = keep_recent.min(messages.len());
    if messages.len() <= keep { return Ok(0); }
    let remove_count = messages.len() - keep;
    let removed: Vec<Message> = messages.drain(..remove_count).collect();
    save_transcript(project_path, &removed)?;
    let summary = summarize_removed(&removed);
    messages.insert(0, Message {
        role: Role::System,
        content: format!("[Conversation summary: {summary}]"),
        tool_calls: None, tool_call_id: None,
    });
    Ok(remove_count)
}

/// Tier 3 - Summarize: save everything, replace with structured summary.
pub fn summarize_compact(messages: &mut Vec<Message>, project_path: &Path) -> Result<String> {
    save_transcript(project_path, messages)?;
    let summary = summarize_removed(messages);
    messages.clear();
    messages.push(Message {
        role: Role::System,
        content: format!("[Session summary]\n\n{summary}"),
        tool_calls: None, tool_call_id: None,
    });
    Ok(summary)
}
```

The key insight: Tier 1 runs every turn with zero cost (just string replacement). Most sessions never hit Tier 2. Tier 3 is a last resort that requires reinjecting identity and tool definitions afterward.

```rust
/// Tier 1 - Microcompact: replace old tool_result content with placeholders.
/// Keeps the last 3 tool results intact. Preserves file_read results always.
pub fn micro_compact(messages: &mut Vec<Message>) -> usize {
    // Collect indices of all tool-result messages
    let tool_result_indices: Vec<usize> = messages
        .iter()
        .enumerate()
        .filter(|(_, m)| m.role == Role::Tool)
        .map(|(i, _)| i)
        .collect();

    // Keep the last 3 intact
    if tool_result_indices.len() <= 3 {
        return 0;
    }
    let cutoff = tool_result_indices.len() - 3;
    let mut compacted = 0;

    for &idx in &tool_result_indices[..cutoff] {
        let msg = &messages[idx];

        // Already compacted - skip
        if msg.content.starts_with("[Previous: used ") {
            continue;
        }

        // Resolve tool name from the matching assistant tool_call
        let tool_name = if let Some(ref tc_id) = msg.tool_call_id {
            find_tool_name_for_call(messages, tc_id, idx)
        } else {
            None
        };
        let tool_name = tool_name.unwrap_or_else(|| "tool".to_string());

        // Exception: preserve file_read results (reference material)
        if tool_name == "file_read" {
            continue;
        }

        messages[idx].content = format!("[Previous: used {tool_name}]");
        compacted += 1;
    }

    compacted
}

fn find_tool_name_for_call(messages: &[Message], call_id: &str, before_idx: usize) -> Option<String> {
    for msg in messages[..before_idx].iter().rev() {
        if msg.role == Role::Assistant {
            if let Some(ref calls) = msg.tool_calls {
                for tc in calls {
                    if tc.id == call_id {
                        return Some(tc.name.clone());
                    }
                }
            }
        }
    }
    None
}
```

Why preserve file_read: the model references file contents when making edits. If you compact away a file_read result, the model will either re-read the file (wasting a tool call) or hallucinate the contents. Bash output and grep results are ephemeral; file contents are structural.

```rust
use serde::{Deserialize, Serialize};
use std::collections::HashMap;
use std::path::Path;
use std::time::{SystemTime, UNIX_EPOCH};

/// Structured session state that survives total context loss.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct SessionCheckpoint {
    pub timestamp: u64,
    pub files_modified: Vec<String>,
    pub tools_used: Vec<(String, usize)>,
    pub errors_encountered: Vec<String>,
    pub last_user_request: Option<String>,
    pub pending_work: Option<String>,
}

pub fn extract_session_memory(messages: &[Message], project_path: &Path) -> Result<PathBuf> {
    let checkpoint = SessionCheckpoint {
        timestamp: SystemTime::now().duration_since(UNIX_EPOCH)
            .unwrap_or_default().as_secs(),
        files_modified: extract_modified_files(messages),
        tools_used: extract_tool_usage(messages),
        errors_encountered: extract_errors(messages),
        last_user_request: extract_last_user_message(messages),
        pending_work: extract_pending_work(messages),
    };

    let dir = project_path.join(".ftai").join("checkpoints");
    std::fs::create_dir_all(&dir)?;
    let path = dir.join(format!("{}.json", checkpoint.timestamp));
    std::fs::write(&path, serde_json::to_string_pretty(&checkpoint)?)?;
    Ok(path)
}

fn extract_modified_files(messages: &[Message]) -> Vec<String> {
    let mut files = Vec::new();
    for msg in messages {
        if let Some(ref calls) = msg.tool_calls {
            for tc in calls {
                if tc.name == "file_write" || tc.name == "file_edit" {
                    if let Some(path) = tc.arguments.get("path").and_then(|v| v.as_str()) {
                        if !files.contains(&path.to_string()) {
                            files.push(path.to_string());
                        }
                    }
                }
            }
        }
    }
    files
}

fn extract_tool_usage(messages: &[Message]) -> Vec<(String, usize)> {
    let mut counts: HashMap<String, usize> = HashMap::new();
    for msg in messages {
        if let Some(ref calls) = msg.tool_calls {
            for tc in calls { *counts.entry(tc.name.clone()).or_default() += 1; }
        }
    }
    let mut result: Vec<_> = counts.into_iter().collect();
    result.sort_by(|a, b| b.1.cmp(&a.1));
    result
}
```

This checkpoint gets written to disk before Tier 3 compaction. After the context is cleared and reinjected with the summary, the model can read the checkpoint via `file_read` to recover exact file paths it was editing, the last user request, and any errors it was debugging.

