/// Cross-platform path escape detection.
fn is_path_escape(path: &str) -> bool {
    if path.contains("..") { return true; }           // traversal
    if path.starts_with('/') { return true; }           // Unix absolute
    if path.contains("..\\") { return true; }          // Windows backslash traversal
    if path.len() >= 2 && path.as_bytes()[0].is_ascii_alphabetic()
        && path.as_bytes()[1] == b':' { return true; }  // C:\... or D:/...
    if path.starts_with("\\\\") { return true; }       // UNC \\server\share
    false
}

pub fn load_manifest(plugin_dir: &Path) -> Result<PluginManifest> {
    let manifest_path = plugin_dir.join("plugin.toml");
    let content = std::fs::read_to_string(&manifest_path)
        .with_context(|| format!("Failed to read {}", manifest_path.display()))?;
    let manifest: PluginManifest = toml::from_str(&content)
        .with_context(|| format!("Failed to parse {}", manifest_path.display()))?;

    // Validate plugin name: alphanumeric + hyphens only
    if !manifest.plugin.name.chars().all(|c| c.is_alphanumeric() || c == '-' || c == '_') {
        anyhow::bail!("Invalid plugin name '{}'", manifest.plugin.name);
    }

    // Validate all command/file paths are relative and don't escape
    for tool in &manifest.tools {
        if is_path_escape(&tool.command) {
            anyhow::bail!("Tool command '{}' must be relative to plugin dir", tool.command);
        }
    }
    for hook in &manifest.hooks {
        if is_path_escape(&hook.command) {
            anyhow::bail!("Hook command '{}' must be relative to plugin dir", hook.command);
        }
    }
    for skill in &manifest.skills {
        if is_path_escape(&skill.file) {
            anyhow::bail!("Skill file '{}' must be relative to plugin dir", skill.file);
        }
    }

    Ok(manifest)
}
```

The `is_path_escape` function blocks five attack vectors: Unix traversal (`..`), Unix absolute (`/usr/bin/rm`), Windows backslash traversal (`..\..\`), Windows drive letters (`C:\`), and UNC paths (`\\server\share`). All checked on every platform because a manifest could be authored on Windows and loaded on Unix.

