use anyhow::{Context, Result};
use std::path::{Path, PathBuf};

pub struct LoadedPlugin {
    pub manifest: PluginManifest,
    pub dir: PathBuf,
}

pub struct PluginManager {
    plugins_dir: PathBuf,
    plugins: Vec<LoadedPlugin>,
}

impl PluginManager {
    pub fn new(plugins_dir: PathBuf) -> Self {
        Self { plugins_dir, plugins: Vec::new() }
    }

    pub fn load_all(&mut self) -> Result<usize> {
        self.plugins.clear();
        if !self.plugins_dir.exists() { return Ok(0); }
        let entries = std::fs::read_dir(&self.plugins_dir)?;
        for entry in entries {
            let path = entry?.path();
            if !path.is_dir() { continue; }
            if !path.join("plugin.toml").exists() { continue; }
            match manifest::load_manifest(&path) {
                Ok(m) => self.plugins.push(LoadedPlugin { manifest: m, dir: path }),
                Err(e) => eprintln!("Warning: failed to load plugin at {}: {e}", path.display()),
            }
        }
        Ok(self.plugins.len())
    }

    pub fn uninstall(&mut self, name: &str) -> Result<()> {
        let dir = self.plugins_dir.join(name);
        if !dir.exists() { anyhow::bail!("Plugin '{name}' not installed"); }

        // Path traversal guard: canonicalize and verify containment
        let canonical_dir = dir.canonicalize()?;
        let canonical_plugins = self.plugins_dir.canonicalize()?;
        if !canonical_dir.starts_with(&canonical_plugins) {
            anyhow::bail!("Plugin path escapes plugins directory");
        }

        std::fs::remove_dir_all(&dir)?;
        self.plugins.retain(|p| p.manifest.plugin.name != name);
        Ok(())
    }

    pub fn get_tools(&self) -> Vec<PluginTool> {
        self.plugins.iter().flat_map(|plugin| {
            plugin.manifest.tools.iter().map(move |td| PluginTool::new(
                format!("plugin:{}:{}", plugin.manifest.plugin.name, td.name),
                td.description.clone(),
                td.command.clone(),
                plugin.dir.clone(),
                td.params.clone(),
            ))
        }).collect()
    }
}
```

The uninstall path traversal guard is critical: without `canonicalize()` + `starts_with()`, an attacker could call `uninstall("../important-data")` and delete arbitrary directories. The `plugin:` namespace prefix on tool names prevents plugins from impersonating built-in tools like `bash`.

Defense in depth. The manifest parser and plugin manager check at different layers with different information:

**Manifest parser** (load time): validates the raw string from the TOML file.
```rust
for hook in &manifest.hooks {
    if is_path_escape(&hook.command) {
        anyhow::bail!("Invalid hook command: must be relative");
    }
}
```
This catches `../../etc/passwd`, `/usr/bin/rm`, `C:\Windows\cmd.exe` before the plugin is even loaded.

**Plugin manager** (execution time): resolves the command path and validates it stays inside the plugin directory.
```rust
pub fn get_hooks(&self, event: &str) -> Vec<ResolvedHook> {
    for hook_def in &plugin.manifest.hooks {
        if hook_def.event == event {
            // Validate command doesn't escape
            if hook_def.command.contains("..")
                || hook_def.command.starts_with('/')
                || hook_def.command.starts_with("\\\\")
                || (hook_def.command.len() >= 2
                    && hook_def.command.as_bytes()[0].is_ascii_alphabetic()
                    && hook_def.command.as_bytes()[1] == b':') {
                continue; // silently skip
            }
            hooks.push(ResolvedHook {
                command_path: plugin.dir.join(&hook_def.command),
                // ...
            });
        }
    }
}
```

Why both? Because the manifest could be modified after loading (TOCTOU), or the plugin directory itself could contain symlinks. The manifest check catches the obvious attack. The manager check catches the subtle one where the file on disk changes between load and execution.

The manager also silently skips bad hooks rather than failing, because a single bad hook shouldn't prevent other plugins from working. The manifest parser, by contrast, rejects the entire plugin - you want to know at install time that something is wrong.

