#[serde(default)]
pub struct ModelConfig {
    pub backend: BackendType,
    pub path: Option<String>,
    pub context_length: usize,
    pub temperature: f64,
}

impl Default for ModelConfig {
    fn default() -> Self {
        Self {
            backend: BackendType::Mlx,
            path: None,
            context_length: 32768,
            temperature: 0.3,
        }
    }
}

pub fn global_config_dir() -> Result<PathBuf> {
    let home = dirs::home_dir().context("No home directory")?;
    Ok(home.join(".ftai"))
}

pub fn project_config_dir(project_path: &Path) -> Result<PathBuf> {
    let global = global_config_dir()?;
    let encoded = project_path.to_string_lossy()
        .replace(['/', '\\'], "-")
        .trim_start_matches('-').to_string();
    Ok(global.join("projects").join(encoded))
}

/// Load config with precedence: project .ftai/ > user project override > global
pub fn load_config(project_path: Option<&Path>) -> Result<Config> {
    let global_dir = global_config_dir()?;
    let mut config = Config::default();

    // Layer 1: Global (~/.ftai/config.toml)
    let global_path = global_dir.join("config.toml");
    if global_path.exists() {
        let contents = std::fs::read_to_string(&global_path)?;
        config = toml::from_str(&contents)?;
    }

    if let Some(project) = project_path {
        // Layer 2: User per-project (~/.ftai/projects/<encoded>/config.toml)
        let user_project = project_config_dir(project)?.join("config.toml");
        if user_project.exists() {
            let contents = std::fs::read_to_string(&user_project)?;
            let override_cfg: Config = toml::from_str(&contents)?;
            config = merge_config(config, override_cfg);
        }

        // Layer 3: In-repo (<project>/.ftai/config.toml)
        let repo_config = project.join(".ftai").join("config.toml");
        if repo_config.exists() {
            let contents = std::fs::read_to_string(&repo_config)?;
            let override_cfg: Config = toml::from_str(&contents)?;
            config = merge_config(config, override_cfg);
        }
    }

    Ok(config)
}

fn merge_config(base: Config, over: Config) -> Config {
    Config {
        model: ModelConfig {
            backend: over.model.backend,
            path: over.model.path.or(base.model.path),
            context_length: over.model.context_length,
            temperature: over.model.temperature,
        },
        permissions: over.permissions,
        paths: PathsConfig {
            models_dir: over.paths.models_dir.or(base.paths.models_dir),
            rules_file: over.paths.rules_file.or(base.paths.rules_file),
        },
        plugins: over.plugins,
    }
}
```

The merge strategy for `Option` fields uses `.or()` so an unset field in the override falls through to the base. Non-optional fields (like `context_length`) always take the override value since `#[serde(default)]` fills them with defaults when not present in the TOML.

```rust
pub fn build_system_prompt(
    project_path: &Path,
    tool_defs: &[ToolDefinition],
    rules_summary: Option<&str>,
    memory_context: Option<&str>,
    templates: Option<&TemplateSet>,
    enabled_templates: &[String],
    ftai_context: Option<&str>,
    plugin_skills: Option<&str>,
) -> String {
    let mut parts = Vec::new();

    // 1. Core identity
    parts.push(format!(
        "You are Forge, a FolkTech AI terminal coding assistant.\n\
         Current project: {}\n", project_path.display()
    ));

    // 2. FTAI.md project instructions (high priority - before tools)
    if let Some(ctx) = ftai_context {
        parts.push(format!(
            "# Project Instructions\n\
             The following instructions come from FTAI.md. You MUST follow them.\n\n{ctx}\n"
        ));
    }

    // 3. Tool descriptions
    if !tool_defs.is_empty() {
        parts.push("# Available Tools\n".to_string());
        for tool in tool_defs {
            parts.push(format!("## {}\n{}\nParameters: {}\n",
                tool.name, tool.description,
                serde_json::to_string_pretty(&tool.parameters).unwrap_or_default()
            ));
        }
    }

    // 4. Active rules
    if let Some(rules) = rules_summary {
        parts.push(format!("# Active Rules\n{rules}\n"));
    }

    // 5. Memory context
    if let Some(memory) = memory_context {
        parts.push(format!("# Memory\n{memory}\n"));
    }

    // 6. Formatting guidelines (conditional on enabled list)
    if let Some(tmpl) = templates {
        let active = enabled_templates(tmpl, enabled_templates);
        if !active.is_empty() {
            parts.push("# Formatting Guidelines\n".to_string());
            for (label, content) in active {
                parts.push(format!("## {label}\n{content}\n"));
            }
        }
    }

    // 7. Plugin skills
    if let Some(skills) = plugin_skills {
        parts.push(format!("# Available Skills\n{skills}\n"));
    }

    // 8. Behavioral anchors
    parts.push("# Accuracy\nReport outcomes faithfully. Never claim tests pass when output shows failures.\n".to_string());
    parts.push("# Verification\nBefore reporting a task complete, verify it works.\n".to_string());
    parts.push("# Output Efficiency\nGo straight to the point. Skip filler and preamble.\n".to_string());

    parts.join("\n")
}
```

Order matters: identity comes first so the model knows who it is. FTAI.md comes before tools because project instructions should override default behavior. Behavioral anchors come last as persistent reminders.

The function also loads git context (branch, dirty status) and injects it under `# Environment`.

```rust
pub fn build_chat_system_prompt(
    memory_context: Option<&str>,
    ftai_context: Option<&str>,
) -> String {
    let mut parts = Vec::new();

    parts.push(
        "You are Forge, a FolkTech AI assistant. \
         You can help with coding, answer questions, discuss ideas, and have general conversations.\n\
         \n\
         Only use tools when the user explicitly asks you to perform an action."
            .to_string(),
    );

    if let Some(ctx) = ftai_context {
        parts.push(format!("# Instructions\n{ctx}\n"));
    }

    if let Some(memory) = memory_context {
        parts.push(format!("# Memory\n{memory}\n"));
    }

    parts.join("\n")
}
```

The chat prompt deliberately omits:
- Tool definitions (saves ~2K tokens)
- Active rules (not relevant for conversation)
- Formatting guidelines (no commits or PRs)
- Behavioral anchors about verification (not applicable)

The `Only use tools when the user explicitly asks` instruction is critical. Without it, the model in chat mode will still attempt tool calls because tools are registered at the API level even when not described in the prompt. This single sentence prevents unnecessary tool invocations during casual conversation.

Test that chat prompt is strictly shorter than coding prompt:
```rust
#[test]
fn test_chat_shorter_than_coding() {
    let coding = build_system_prompt(&PathBuf::from("/tmp"), &[], None, None, None, &[], None, None);
    let chat = build_chat_system_prompt(None, None);
    assert!(chat.len() < coding.len());
}
```

FTAI.md is the equivalent of Claude's CLAUDE.md - project instructions that the AI must follow. It loads from two layers:

```rust
const FTAI_CONTEXT_MAX_CHARS: usize = 10_000;

pub fn load_ftai_context(project_path: &Path) -> Option<String> {
    let mut parts = Vec::new();

    // Global layer (~/.ftai/FTAI.md)
    if let Ok(global_dir) = global_config_dir() {
        if let Some(content) = read_ftai_file(&global_dir) {
            parts.push(format!("## Global Instructions\n{content}"));
        }
    }

    // Project layer (<project>/.ftai/FTAI.md)
    let project_ftai_dir = project_path.join(".ftai");
    if let Some(content) = read_ftai_file(&project_ftai_dir) {
        parts.push(format!("## Project Instructions\n{content}"));
    }

    if parts.is_empty() { return None; }
    let mut combined = parts.join("\n---\n");

    // Truncate with warning
    if combined.len() > FTAI_CONTEXT_MAX_CHARS {
        combined.truncate(FTAI_CONTEXT_MAX_CHARS);
        combined.push_str("\n\n[WARNING: FTAI.md content truncated at 10,000 characters]");
    }
    Some(combined)
}

fn read_ftai_file(dir: &Path) -> Option<String> {
    let ftai_md = dir.join("FTAI.md");
    if ftai_md.exists() {
        return std::fs::read_to_string(&ftai_md).ok().filter(|s| !s.trim().is_empty());
    }
    let context_ftai = dir.join("context.ftai");
    if context_ftai.exists() {
        return std::fs::read_to_string(&context_ftai).ok().filter(|s| !s.trim().is_empty());
    }
    None
}
```

Why 10K chars (~2,500 tokens):
- With a 32K context window and ~6K tokens of system prompt overhead (identity + tools + rules + anchors), you have ~26K for conversation.
- Allowing FTAI.md to consume more than 10K would eat into conversation space, triggering compaction earlier.
- 10K chars is enough for comprehensive project instructions (architecture overview, coding conventions, known issues).
- The truncation warning tells the model (and indirectly the user) that content was cut, so they know to split into smaller files.

FTAI.md is preferred over context.ftai (fallback) because markdown is more readable and supports formatting that both humans and models understand.

```rust
use std::collections::HashMap;

const MIN_PATTERN_SESSIONS: usize = 3;
const MIN_SKILL_SUCCESS_RATE: f64 = 0.70;
const MIN_SEQUENCE_LEN: usize = 2;

#[derive(Debug, Clone)]
pub struct ToolPattern {
    pub tool_sequence: Vec<String>,
    pub occurrence_count: usize,
    pub avg_success_rate: f64,
    pub common_args: HashMap<String, String>,
}

impl ToolPattern {
    pub fn is_significant(&self) -> bool {
        self.occurrence_count >= MIN_PATTERN_SESSIONS
            && self.avg_success_rate >= MIN_SKILL_SUCCESS_RATE
    }
}

pub struct SkillBuilder;

impl SkillBuilder {
    pub fn detect_patterns(outcomes: &[SessionOutcome]) -> Vec<ToolPattern> {
        let mut pattern_map: HashMap<Vec<String>, PatternAccum> = HashMap::new();

        for outcome in outcomes {
            let tools: Vec<String> = outcome.tool_calls.iter()
                .map(|tc| tc.tool_name.clone()).collect();

            // All contiguous windows of length 2..N
            for len in MIN_SEQUENCE_LEN..=tools.len() {
                for window in tools.windows(len) {
                    let key = window.to_vec();
                    let accum = pattern_map.entry(key).or_default();
                    if !accum.session_ids.contains(&outcome.session_id) {
                        accum.session_ids.push(outcome.session_id.clone());
                        if outcome.success.is_success() {
                            accum.success_count += 1;
                        }
                    }
                }
            }
        }

        pattern_map.into_iter().map(|(seq, accum)| {
            let total = accum.session_ids.len();
            ToolPattern {
                tool_sequence: seq,
                occurrence_count: total,
                avg_success_rate: if total == 0 { 0.0 }
                    else { accum.success_count as f64 / total as f64 },
                common_args: HashMap::new(),
            }
        }).collect()
    }

    pub fn analyze_sessions(outcomes: &[SessionOutcome]) -> Vec<SkillTemplate> {
        Self::detect_patterns(outcomes)
            .iter()
            .filter(|p| p.is_significant())
            .map(|p| Self::pattern_to_skill(p, outcomes))
            .collect()
    }
}
```

The sliding window approach extracts all contiguous sub-sequences of length 2+. If `[file_read, file_edit, bash]` appears in 3+ successful sessions, it becomes a skill template. The template includes:
- A trigger command (`/file_read-file_edit-bash`)
- A workflow description with numbered steps
- Common argument patterns extracted by majority vote on whitespace-split tokens

Skills are saved as markdown files with embedded JSON metadata for round-tripping.

```rust
impl SkillBuilder {
    pub fn save_skill(skill: &SkillTemplate, skills_dir: &Path) -> Result<()> {
        std::fs::create_dir_all(skills_dir)?;

        // Sanitize: only alphanumeric, hyphen, underscore
        let safe_name = sanitize_skill_name(&skill.name);
        if safe_name.is_empty() {
            anyhow::bail!("Skill name '{}' sanitizes to empty", skill.name);
        }

        let filename = format!("{safe_name}.md");
        let skill_path = skills_dir.join(&filename);

        // Path traversal guard
        let canonical_dir = skills_dir.canonicalize()?;
        let expected = canonical_dir.join(&filename);
        if !expected.starts_with(&canonical_dir) {
            anyhow::bail!("Skill path escape detected");
        }

        let metadata = serde_json::json!({
            "name": skill.name,
            "trigger": skill.trigger,
            "description": skill.description,
            "confidence": skill.confidence,
        });

        let content = format!(
            "<!-- auto-generated-skill: {} -->\n<!-- metadata: {} -->\n\n{}",
            safe_name, metadata, skill.content
        );
        std::fs::write(&skill_path, content)?;
        Ok(())
    }

    pub fn load_auto_skills(skills_dir: &Path) -> Result<Vec<SkillTemplate>> {
        if !skills_dir.exists() { return Ok(vec![]); }
        let canonical_dir = skills_dir.canonicalize()?;
        let mut skills = Vec::new();

        for entry in std::fs::read_dir(skills_dir)? {
            let path = entry?.path();
            if path.extension().and_then(|e| e.to_str()) != Some("md") { continue; }
            // Security: verify file is inside skills_dir
            if let Ok(canonical) = path.canonicalize() {
                if !canonical.starts_with(&canonical_dir) { continue; }
            }
            let raw = std::fs::read_to_string(&path)?;
            if let Some(skill) = parse_skill_file(&raw) {
                skills.push(skill);
            }
        }
        Ok(skills)
    }
}

fn sanitize_skill_name(input: &str) -> String {
    let mut out = String::with_capacity(input.len());
    let mut last_hyphen = false;
    for ch in input.chars() {
        if ch.is_ascii_alphanumeric() || ch == '_' {
            out.push(ch);
            last_hyphen = false;
        } else if !last_hyphen {
            out.push('-');
            last_hyphen = true;
        }
    }
    out.trim_matches('-').to_string()
}
```

The sanitizer converts `../../evil` to `evil` (dots become hyphens, then leading hyphens are trimmed). Combined with the `canonicalize` + `starts_with` check, there's no way for a generated skill name to escape the skills directory.

The `escape_for_prompt` function sanitizes argument strings before embedding them in skill content, preventing LLM output injection:
```rust
fn escape_for_prompt(input: &str) -> String {
    let mut s = input.replace('\\', "\\\\");
    s = s.replace('`', "'");
    s = s.replace('\n', " ");
    if s.len() > 200 { s.truncate(200); }
    s
}
```

```rust
pub struct DreamRunner {
    project_path: PathBuf,
    dream_dir: PathBuf,
    transcripts_dir: PathBuf,
    memory_dir: PathBuf,
}

impl DreamRunner {
    pub fn new(project_path: &Path) -> Self {
        let ftai = project_path.join(".ftai");
        Self {
            project_path: project_path.to_path_buf(),
            dream_dir: ftai.join("dreams"),
            transcripts_dir: ftai.join("transcripts"),
            memory_dir: ftai.join("memory"),
        }
    }

    pub fn run(&self, since_time: Option<u64>) -> Result<PathBuf> {
        self.validate_paths()?; // all paths must be inside .ftai
        std::fs::create_dir_all(&self.dream_dir)?;
        std::fs::create_dir_all(&self.memory_dir)?;

        // Phase 1: Orient - read existing memories
        let existing = self.phase1_orient();

        // Phase 2: Gather signal from transcripts
        let signal = self.phase2_gather_signal(since_time.unwrap_or(0));
        if signal.session_count == 0 {
            // Write empty dream and return
            let path = self.dream_dir.join("latest.md");
            std::fs::write(&path, "No sessions found since last dream.")?;
            return Ok(path);
        }

        // Phase 3: Consolidate memory (hot files, repeated errors)
        let memory_updates = self.phase3_consolidate_memory(&signal, &existing)?;

        // Phase 4: Analyze unresolved error patterns
        let analyses = self.phase4_analyze(&signal)?;

        // Phase 5: Write latest.md summary
        self.phase5_write_summary(&signal, &memory_updates, &analyses)
    }

    fn phase2_gather_signal(&self, since_time: u64) -> Signal {
        let mut signal = Signal::default();
        for entry in std::fs::read_dir(&self.transcripts_dir).into_iter().flatten().flatten() {
            let path = entry.path();
            if path.extension().map_or(true, |e| e != "jsonl") { continue; }
            // Security: canonical path must be inside transcripts_dir
            if let Ok(canonical) = path.canonicalize() {
                if let Ok(canon_dir) = self.transcripts_dir.canonicalize() {
                    if !canonical.starts_with(&canon_dir) { continue; }
                }
            }
            // Parse JSONL, extract tool counts, file counts, errors, topics
            if let Ok(content) = std::fs::read_to_string(&path) {
                for line in content.lines() {
                    if let Ok(msg) = serde_json::from_str::<Value>(line) {
                        self.extract_from_message(&msg, &mut signal);
                    }
                }
                signal.session_count += 1;
            }
        }
        signal
    }

    fn phase3_consolidate_memory(&self, signal: &Signal, _: &[(String, String)]) -> Result<Vec<String>> {
        let mut updates = Vec::new();
        // Write hot-files.md for files edited >= 3 times
        let hot: Vec<_> = signal.file_counts.iter().filter(|(_, c)| **c >= 3).collect();
        if !hot.is_empty() {
            let content = hot.iter().map(|(p, c)| format!("- {p} ({c} edits)")).collect::<Vec<_>>().join("\n");
            std::fs::write(self.memory_dir.join("hot-files.md"), content)?;
            updates.push("Updated: hot-files".into());
        }
        Ok(updates)
    }
}
```

The dream is injected into the next session if it's < 48 hours old:
```rust
pub fn dream_context_for_session(project_path: &Path) -> Option<String> {
    let path = project_path.join(".ftai/dreams/latest.md");
    let age = path.metadata().ok()?.modified().ok()
        .and_then(|t| SystemTime::now().duration_since(t).ok())?;
    if age.as_secs() > 48 * 60 * 60 { return None; }
    std::fs::read_to_string(&path).ok().filter(|s| !s.trim().is_empty())
}
```

The 48-hour TTL prevents stale dreams from polluting new sessions. The 5-phase pipeline is deterministic (no model calls), so it runs instantly as a post-session hook.

```rust
fn prune_stale_memories(&self, signal: &Signal) -> Result<()> {
    if !self.memory_dir.exists() { return Ok(()); }

    let now = SystemTime::now().duration_since(UNIX_EPOCH)
        .unwrap_or_default().as_secs();
    let thirty_days = 30 * 24 * 60 * 60;

    if let Ok(entries) = std::fs::read_dir(&self.memory_dir) {
        for entry in entries.flatten() {
            let path = entry.path();
            if path.extension().map_or(true, |e| e != "md") { continue; }

            // Check age
            let mtime = path.metadata().ok()
                .and_then(|m| m.modified().ok())
                .and_then(|t| t.duration_since(UNIX_EPOCH).ok())
                .map(|d| d.as_secs())
                .unwrap_or(0);

            if now.saturating_sub(mtime) <= thirty_days {
                continue; // Not stale yet
            }

            // Check if referenced in recent session topics or errors
            let name = path.file_stem().unwrap_or_default()
                .to_string_lossy().to_lowercase();
            let is_referenced = signal.topics.iter()
                .any(|t| t.to_lowercase().contains(&name))
                || signal.errors.iter()
                .any(|e| e.to_lowercase().contains(&name));

            if !is_referenced {
                // Security: verify path is inside memory_dir before deleting
                if let Ok(canon) = path.canonicalize() {
                    if let Ok(canon_dir) = self.memory_dir.canonicalize() {
                        if canon.starts_with(&canon_dir) {
                            let _ = std::fs::remove_file(&path);
                        }
                    }
                }
            }
        }
    }
    Ok(())
}
```

Key design decisions:

1. **Reference check before delete**: A memory about "auth-design" survives if any recent session topic or error mentions "auth-design". This prevents deleting memories that are still relevant even if the file is old.

2. **Canonical path validation**: Even though we're iterating files inside memory_dir, symlinks could point outside. The `canonicalize` + `starts_with` check prevents deleting files outside the memory directory.

3. **`saturating_sub`**: Prevents underflow if the system clock is wrong (mtime in the future). Without this, `now - mtime` would wrap to u64::MAX and the file would be incorrectly considered stale.

4. **Silent failure on delete**: `let _ = std::fs::remove_file()` ignores errors because a failed prune is non-critical. The memory just persists until the next dream run.

