pub fn load_memory_context(project_path: &Path) -> Option<String> {
    let mut parts = Vec::new();

    // Global memories (~/.ftai/memory/)
    if let Ok(global_dir) = crate::config::global_config_dir() {
        let global_memory_dir = global_dir.join("memory");
        if let Some(content) = load_memory_layer(&global_memory_dir) {
            parts.push(format!("## Global Memory\n{content}"));
        }
    }

    // Project memories (<project>/.ftai/memory/)
    let project_memory_dir = project_path.join(".ftai").join("memory");
    if let Some(content) = load_memory_layer(&project_memory_dir) {
        parts.push(format!("## Project Memory\n{content}"));
    }

    // User-specific project memories (~/.ftai/projects/<encoded>/memory/)
    if let Ok(project_dir) = crate::config::project_config_dir(project_path) {
        let user_project_memory = project_dir.join("memory");
        if let Some(content) = load_memory_layer(&user_project_memory) {
            parts.push(format!("## User Project Memory\n{content}"));
        }
    }

    if parts.is_empty() { None }
    else { Some(parts.join("\n---\n")) }
}

fn load_memory_layer(dir: &Path) -> Option<String> {
    if !dir.exists() { return None; }
    let mut entries = Vec::new();

    if let Ok(files) = read_memory_dir(dir, None) {
        for (name, content) in files {
            if name == "MEMORY" {
                // Legacy format: include as-is
                if !content.trim().is_empty() { entries.push(content); }
                continue;
            }
            if !content.trim().is_empty() {
                entries.push(format!("### {name}\n{content}"));
            }
        }
    }

    if entries.is_empty() { None }
    else { Some(entries.join("\n")) }
}

pub fn strip_frontmatter(content: &str) -> &str {
    if !content.starts_with("---") { return content; }
    if let Some(end) = content[3..].find("---") {
        let after = &content[end + 6..];
        after.trim_start_matches('\n')
    } else {
        content
    }
}
```

Three layers give different scoping:
- **Global**: preferences that apply everywhere ("User prefers Rust", "Always use snake_case")
- **Project**: facts about this codebase ("Uses PostgreSQL", "JWT with RS256")
- **User-project**: personal overrides for shared repos (not committed to git)

The legacy `MEMORY.md` format (bullet-point list) is supported for backward compatibility but new memories use individual files with YAML frontmatter for categorization.

```rust
pub fn build_git_context(project_path: &Path) -> Option<String> {
    // Walk up to find .git directory
    let mut dir = project_path.to_path_buf();
    let git_root = loop {
        if dir.join(".git").exists() { break dir; }
        if !dir.pop() { return None; }
    };

    // Read HEAD directly for branch name (no git dependency)
    let head_path = git_root.join(".git").join("HEAD");
    let head_content = std::fs::read_to_string(&head_path).ok()?;
    let branch = if let Some(ref_line) = head_content.strip_prefix("ref: refs/heads/") {
        ref_line.trim().to_string()
    } else {
        // Detached HEAD - use short hash
        head_content.trim().chars().take(8).collect()
    };

    // Get dirty status via git diff (requires git binary)
    let is_dirty = std::process::Command::new("git")
        .args(["diff", "--quiet", "HEAD"])
        .current_dir(&git_root)
        .stdout(std::process::Stdio::null())
        .stderr(std::process::Stdio::null())
        .status()
        .ok()
        .map(|s| !s.success())
        .unwrap_or(false);

    let diff_stats = if is_dirty {
        let output = std::process::Command::new("git")
            .args(["diff", "HEAD", "--shortstat"])
            .current_dir(&git_root)
            .output().ok()?;
        let stats = String::from_utf8_lossy(&output.stdout).trim().to_string();
        if stats.is_empty() { "dirty (untracked changes)".to_string() }
        else { stats }
    } else {
        "clean".to_string()
    };

    Some(format!("Git: branch={branch}, status={diff_stats}, root={}", git_root.display()))
}
```

Branch detection reads `.git/HEAD` directly (no subprocess). This is fast and works even if git isn't installed. Dirty status uses the git binary because parsing the index format is complex and fragile.

The result gets injected under `# Environment` in the system prompt, giving the model awareness of the current branch and whether there are uncommitted changes. This is critical for git-related tool calls - the model should know it's on `feature/auth` before running `git commit`.

```rust
pub fn get_hooks(&self, event: &str) -> Vec<ResolvedHook> {
    let mut hooks = Vec::new();
    for plugin in &self.plugins {
        for hook_def in &plugin.manifest.hooks {
            if hook_def.event == event {
                // Validate command doesn't escape (both Unix and Windows patterns)
                if hook_def.command.contains("..")
                    || hook_def.command.starts_with('/')
                    || hook_def.command.starts_with("\\\\")
                    || (hook_def.command.len() >= 2
                        && hook_def.command.as_bytes()[0].is_ascii_alphabetic()
                        && hook_def.command.as_bytes()[1] == b':')
                {
                    continue; // silently skip dangerous hooks
                }
                hooks.push(ResolvedHook {
                    event: hook_def.event.clone(),
                    command_path: plugin.dir.join(&hook_def.command),
                    plugin_dir: plugin.dir.clone(),
                    plugin_name: plugin.manifest.plugin.name.clone(),
                });
            }
        }
    }
    hooks
}
```

Four checks cover the attack surface:
1. `..` - directory traversal on any platform
2. `/` prefix - Unix absolute path
3. `\\` prefix - UNC path (`\\server\share`)
4. Drive letter + colon - Windows absolute (`C:\`, `D:/`)

The resolved hook command becomes `plugin.dir.join(&hook_def.command)`. By ensuring the command is a relative path without traversal, `join` keeps it inside the plugin directory.

Why silently skip instead of erroring: a single bad hook in one plugin shouldn't prevent other plugins' hooks from running. The manifest parser already rejects these at install time - this is the runtime defense-in-depth layer. If we somehow get here with a bad command (TOCTOU, manifest tampered after install), skipping is safer than crashing.

```rust
pub fn install_from_git(&self, url: &str) -> Result<String> {
    // Validate URL doesn't contain shell injection characters
    if url.contains(';') || url.contains('&') || url.contains('|') || url.contains('`') {
        anyhow::bail!("Invalid characters in URL");
    }

    let tmp_dir = self.plugins_dir.join(".tmp-clone");
    let _ = std::fs::remove_dir_all(&tmp_dir);
    std::fs::create_dir_all(&tmp_dir)?;

    let status = std::process::Command::new("git")
        .args(["clone", "--depth=1", url, &tmp_dir.to_string_lossy()])
        .status()
        .context("Failed to run git clone")?;

    if !status.success() {
        let _ = std::fs::remove_dir_all(&tmp_dir);
        anyhow::bail!("git clone failed for {url}");
    }

    let manifest = match manifest::load_manifest(&tmp_dir) {
        Ok(m) => m,
        Err(e) => {
            let _ = std::fs::remove_dir_all(&tmp_dir);
            return Err(e);
        }
    };

    let dest = self.plugins_dir.join(&manifest.plugin.name);
    if dest.exists() {
        let _ = std::fs::remove_dir_all(&tmp_dir);
        anyhow::bail!("Plugin '{}' already installed", manifest.plugin.name);
    }

    copy_dir_recursive(&tmp_dir, &dest)?;
    let _ = std::fs::remove_dir_all(&tmp_dir);
    Ok(manifest.plugin.name)
}
```

The shell injection prevention is straightforward: block `;`, `&`, `|`, and backtick. A URL like `https://evil.com/repo; rm -rf /` would execute the `rm` command if passed to a shell. Since we use `Command::new("git")` with `args()` (not a shell), the OS already handles this correctly for most cases. But the explicit check is defense in depth - if someone changes the implementation to use `sh -c` later, the validation still catches it.

Cleanup is thorough: the temp directory is removed in every error path. The `let _ = std::fs::remove_dir_all()` pattern ignores cleanup errors because they're non-critical.

