use serde::{Serialize, Serializer};

/// Serialize f64 with limited precision to avoid IEEE 754 noise
fn serialize_f64_clean<S: Serializer>(val: &f64, ser: S) -> std::result::Result<S::Ok, S::Error> {
    let rounded = (*val * 10000.0).round() / 10000.0;
    ser.serialize_f64(rounded)
}

#[derive(Debug, Clone, Serialize, Deserialize)]
#[serde(default)]
pub struct ModelConfig {
    pub backend: BackendType,
    pub path: Option<String>,
    pub context_length: usize,
    #[serde(serialize_with = "serialize_f64_clean")]
    pub temperature: f64,
}

impl Default for ModelConfig {
    fn default() -> Self {
        Self {
            backend: BackendType::Mlx,
            path: None,
            context_length: 32768,
            temperature: 0.3_f64,
        }
    }
}
```

The issue: when you write `temperature = 0.3` in a TOML config, Rust parses it as the nearest IEEE 754 double, which is `0.29999999999999998890...`. When you serialize back to TOML, you get `temperature = 0.30000000000000004` (depending on the serializer).

The fix rounds to 4 decimal places during serialization. This is sufficient precision for model configuration (temperature, top_p, etc.) while producing clean output. A user who writes `0.3` gets `0.3` back.

The `0.3_f64` suffix in the default is a documentation hint - it doesn't change the value, but signals that this is a floating-point constant, not an integer.

